import{c as n,Z as a,Q as r,j as i,o,m as l}from"./chunks/framework.qjzPVSkb.js";const m=JSON.parse('{"title":"微调 (Fine-tuning)","description":"在预训练模型基础上用特定数据二次训练，让它适应特定任务或风格","frontmatter":{"title":"微调 (Fine-tuning)","description":"在预训练模型基础上用特定数据二次训练，让它适应特定任务或风格","difficulty":"beginner"},"headers":[],"relativePath":"terms/fine-tuning.md","filePath":"terms/fine-tuning.md"}'),s={name:"terms/fine-tuning.md"};function d(g,t,h,u,f,p){const e=a("DifficultyBadge");return r(),i("div",null,[o(e,{level:"beginner"}),t[0]||(t[0]=l('<h1 id="微调-fine-tuning" tabindex="-1">微调 (Fine-tuning) <a class="header-anchor" href="#微调-fine-tuning" aria-label="Permalink to &quot;微调 (Fine-tuning)&quot;">​</a></h1><p>你有一个通晓万物的通用模型，但你需要它擅长某个特定领域——微调就是为此而生的技术。</p><h2 id="一句话解释" tabindex="-1">一句话解释 <a class="header-anchor" href="#一句话解释" aria-label="Permalink to &quot;一句话解释&quot;">​</a></h2><p>微调（Fine-tuning）是在已预训练好的通用模型基础上，用少量特定领域的数据继续训练，让模型在特定任务上表现更好，同时保留原有的通用能力。LoRA 是目前最流行的高效微调方法。</p><h2 id="通俗类比" tabindex="-1">通俗类比 <a class="header-anchor" href="#通俗类比" aria-label="Permalink to &quot;通俗类比&quot;">​</a></h2><p><strong>通用模型</strong> = 一个医学院刚毕业的全科医生，什么病都能看一点，但都不精。</p><p><strong>微调</strong> = 派他去心血管科轮训 3 个月——他保留原有的医学基础（不会变成只会看心脏），但对心血管疾病特别擅长。</p><ul><li>不需要从头读 8 年医学（重新训练大模型）</li><li>只需要 3 个月专科培训（少量领域数据）</li><li>成本低、见效快</li></ul><h2 id="技术定义" tabindex="-1">技术定义 <a class="header-anchor" href="#技术定义" aria-label="Permalink to &quot;技术定义&quot;">​</a></h2><p>微调的核心是<strong>迁移学习（Transfer Learning）</strong>。数学上，就是在预训练权重的基础上，在特定数据集上继续执行梯度下降。</p><p><strong>全量微调（Full Fine-tuning）</strong> 更新模型的所有参数，效果好但成本高（需要与训练相当的硬件）。</p><p><strong>参数高效微调（PEFT）</strong> 是更实用的方案：</p><table tabindex="0"><thead><tr><th>方法</th><th>原理</th><th>特点</th></tr></thead><tbody><tr><td><strong>LoRA</strong></td><td>在原始权重旁插入可训练的低秩矩阵</td><td>只训练极少参数（&lt;1%），效果接近全量微调</td></tr><tr><td><strong>Adapter</strong></td><td>在 Transformer 层间插入小型网络</td><td>插件式，可堆叠多个适配器</td></tr><tr><td><strong>Prompt Tuning</strong></td><td>只训练一段可学习的 &quot;软提示&quot;</td><td>参数量最小，适合简单任务</td></tr></tbody></table><p>微调的典型应用场景：</p><ul><li><strong>领域定制</strong>：让通用模型精通医疗、法律、金融等专业领域</li><li><strong>风格对齐</strong>：让模型输出符合特定语气、格式或品牌调性</li><li><strong>指令跟随</strong>：提升模型遵循特定类型指令的能力</li><li><strong>知识注入</strong>：补充训练数据截止日期之后的新知识</li></ul><h2 id="关联术语" tabindex="-1">关联术语 <a class="header-anchor" href="#关联术语" aria-label="Permalink to &quot;关联术语&quot;">​</a></h2><ul><li><a href="/ai-knowledge/terms/training-inference.html">训练 / 推理</a> —— 微调是一种特殊的训练</li><li><a href="/ai-knowledge/terms/llm.html">大语言模型 (LLM)</a> —— 微调的主要对象</li><li><a href="/ai-knowledge/terms/parameters.html">参数</a> —— LoRA 只更新极少参数</li></ul><h2 id="快速记忆" tabindex="-1">快速记忆 <a class="header-anchor" href="#快速记忆" aria-label="Permalink to &quot;快速记忆&quot;">​</a></h2><p>好比一个全科医生（通用模型），你让他专攻皮肤科（微调），他只需要补充看皮肤病的数据就行，不需要重新读医学院。</p><h2 id="延伸阅读" tabindex="-1">延伸阅读 <a class="header-anchor" href="#延伸阅读" aria-label="Permalink to &quot;延伸阅读&quot;">​</a></h2><ul><li><a href="https://arxiv.org/abs/2106.09685" target="_blank" rel="noreferrer">LoRA 论文</a> —— Low-Rank Adaptation 原始论文</li><li><a href="https://platform.openai.com/docs/guides/fine-tuning" target="_blank" rel="noreferrer">OpenAI Fine-tuning 指南</a></li><li><a href="https://huggingface.co/docs/peft/index" target="_blank" rel="noreferrer">Hugging Face PEFT 库</a></li></ul>',21))])}const b=n(s,[["render",d]]);export{m as __pageData,b as default};
